oxy_webhelp_navlinks = {"rubrik_backup_service-d27248e3560":{"topics":[{"title":"Obtaining Rubrik Backup Service connector","shortdesc":"<p class=\"shortdesc\">Download the Rubrik Backup Service connector to enable the connected Rubrik clusters         to restore folders and files over corrupted data in the file system on the host.<\/p>","href":"rbs\/rbs_obtaining_connector.html","attributes":{"data-id":"obtaining_rubrik_backup_service_connector"},"menu":{"hasChildren":false},"tocID":"obtaining_rubrik_backup_service_connector-d27248e3571","topics":[]},{"title":"Downloading the RBS software","shortdesc":"<p class=\"shortdesc\">Obtain the Rubrik Backup Service software from the web UI of a Rubrik         cluster.<\/p>","href":"rbs\/rsc_downloading_rbs_software.html","attributes":{"data-id":"rsc_downloading_rbs_software"},"menu":{"hasChildren":false},"tocID":"rsc_downloading_rbs_software-d27248e3582","topics":[]},{"title":"Downloading RBS for cloud-native protection","shortdesc":"<p class=\"shortdesc\">Download the RBS for cloud-native protection to coordinate backup activity between         the Exocompute instance and <span class=\"ph\">RSC<\/span>.<\/p>","href":"rbs\/rbs_downloading_cnp.html","attributes":{"data-id":"rbs_downloading_cnp"},"menu":{"hasChildren":false},"tocID":"rbs_downloading_cnp-d27248e3593","topics":[]},{"title":"RBS installation","shortdesc":"<p class=\"shortdesc\">When installed on host systems, RBS provides integration with protected resources and         coordinates activities between the Rubrik cluster and the host.<\/p>","href":"rbs\/rbs_installation.html","attributes":{"data-id":"rbs_installation_concept"},"menu":{"hasChildren":false},"tocID":"rbs_installation_concept-d27248e3607","next":"rbs_installation_concept-d27248e3607"},{"title":"RBS removal","shortdesc":"<p class=\"shortdesc\">The removal of RBS from a protected host terminates the connection between the host         system and the Rubrik cluster.<\/p>","href":"rbs\/rbs_removal.html","attributes":{"data-id":"rbs_removal_overview"},"menu":{"hasChildren":false},"tocID":"rbs_removal_overview-d27248e3684","next":"rbs_removal_overview-d27248e3684"},{"title":"RBS package verification for platforms based on Linux RPM","shortdesc":"<p class=\"shortdesc\">RBS package verification confirms the authenticity and integrity of the downloaded         package for platforms based on Linux RPM.<\/p>","href":"rbs\/rbs_package_verification.html","attributes":{"data-id":"rbs_package_verification"},"menu":{"hasChildren":false},"tocID":"rbs_package_verification-d27248e3750","topics":[]},{"title":"RBS account on Windows","shortdesc":"<p class=\"shortdesc\">RBS must use an account with local administrators group privileges on the Windows         Server host.<\/p>","href":"rbs\/rbs_account_windows_host.html","attributes":{"data-id":"rbs_account_windows_host"},"menu":{"hasChildren":false},"tocID":"rbs_account_windows_host-d27248e3761","topics":[]},{"title":"Deploying RBS automatically","shortdesc":"<p class=\"shortdesc\">A Rubrik cluster can automatically install and register RBS on a supported Windows         guest at the next scheduled or on-demand backup of that Windows virtual machine.<\/p>","href":"rbs\/rsc_deploying_rbs_automatically.html","attributes":{"data-id":"rsc_deploying_rbs_automatically"},"menu":{"hasChildren":false},"tocID":"rsc_deploying_rbs_automatically-d27248e3772","topics":[]},{"title":"Minimum RBS privileges for Windows","shortdesc":"<p class=\"shortdesc\">RBS requires certain privileges and permissions on Windows for both installation and         regular operations.<\/p>","href":"rbs\/rbs_min_privileges_windows.html","attributes":{"data-id":"rbs_min_privileges_windows"},"menu":{"hasChildren":false},"tocID":"rbs_min_privileges_windows-d27248e3783","topics":[]},{"title":"Determine when RBS is running on a Windows system","shortdesc":"<p class=\"shortdesc\">View the status of RBS on a Windows system.<\/p>","href":"rbs\/determining_if_rbs_runs_windows_sys.html","attributes":{"data-id":"determining_if_rbs_runs_windows_sys"},"menu":{"hasChildren":false},"tocID":"determining_if_rbs_runs_windows_sys-d27248e3794","topics":[]},{"title":"Commands for obtaining RBS status on a non-Windows system","shortdesc":"<p class=\"shortdesc\">You can view the status of RBS on a non-Windows system. The method to view the status         depends on the platform RBS is running on.<\/p>","href":"rbs\/rbs_status_commands_non_windows_sys.html","attributes":{"data-id":"rbs_status_commands_non_windows_sys"},"menu":{"hasChildren":false},"tocID":"rbs_status_commands_non_windows_sys-d27248e3806","topics":[]},{"title":"RBS firewall rules","shortdesc":"<p class=\"shortdesc\">The firewall on the host must allow communication with the ports used by         RBS.<\/p>","href":"rbs\/rsc_rbs_firewall_rules.html","attributes":{"data-id":"rsc_rbs_firewall_rules"},"menu":{"hasChildren":false},"tocID":"rsc_rbs_firewall_rules-d27248e3817","topics":[]},{"title":"RBS log locations","shortdesc":"<p class=\"shortdesc\">You can use RBS logs to determine the root cause of issues. The location of files         used by RBS varies by operating system.<\/p>","href":"rbs\/rbs_log_locations.html","attributes":{"data-id":"rbs_log_locations"},"menu":{"hasChildren":false},"tocID":"rbs_log_locations-d27248e3828","topics":[]},{"title":"RBS registration to multiple Rubrik clusters","shortdesc":"<p class=\"shortdesc\">A single RBS host can connect to multiple Rubrik clusters. <\/p>","href":"saas\/multi_cluster_rbs.html","attributes":{"data-id":"multi_cluster_rbs"},"menu":{"hasChildren":false},"tocID":"multi_cluster_rbs-d27248e3839","topics":[]},{"title":"Host registration with RBS on multiple clusters","shortdesc":"<p class=\"shortdesc\">A Rubrik Backup Service host can be registered to multiple Rubrik clusters by adding         the host to both source and target clusters.<\/p>","href":"saas\/rbs_host_registration_multiple_clusters.html","attributes":{"data-id":"rbs_host_registration_multiple_clusters"},"menu":{"hasChildren":false},"tocID":"rbs_host_registration_multiple_clusters-d27248e3850","topics":[]},{"title":"Changing the primary Rubrik cluster of a host","shortdesc":"<p class=\"shortdesc\">When RBS installed on a host is registered with multiple Rubrik clusters, you can use             <span class=\"ph\">RSC<\/span> to change the primary Rubrik cluster of a host.<\/p>","href":"saas\/changing_primary_cluster_host.html","attributes":{"data-id":"changing_primary_cluster_host"},"menu":{"hasChildren":false},"tocID":"changing_primary_cluster_host-d27248e3861","topics":[]},{"title":"Installing RBS remotely on multiple hosts","shortdesc":"<p class=\"shortdesc\">From <span class=\"ph\">RSC<\/span>, you can install RBS remotely to manage and protect multiple         Linux, Solaris, HP-UX, AIX, or Windows hosts.<\/p>","href":"rbs\/rbs_remote_installing_multiple_hosts.html","attributes":{"data-id":"rbs_remote_installing_multiple_hosts"},"menu":{"hasChildren":false},"tocID":"rbs_remote_installing_multiple_hosts-d27248e3875","topics":[]},{"title":"RBS management commands","shortdesc":"<p class=\"shortdesc\">List of commands to manage RBS on different operating systems.<\/p>","href":"rbs\/rbs_management_commands.html","attributes":{"data-id":"rbs_management_commands"},"menu":{"hasChildren":false},"tocID":"rbs_management_commands-d27248e3889","topics":[]},{"title":"RBS network throttling","shortdesc":"<p class=\"shortdesc\">RBS manages data backups and may consume all network bandwidth, affecting other         applications. Network throttling helps to limit the usage of RBS bandwidth and ensures that         essential services remain unaffected.<\/p>","href":"rbs\/rbs_network_throttling.html","attributes":{"data-id":"rbs_network_throttling"},"menu":{"hasChildren":false},"tocID":"rbs_network_throttling-d27248e3900","next":"rbs_network_throttling-d27248e3900"}]}};